<div class="container py-4"><div class="d-flex justify-content-between align-items-center mb-3"><h1 class="h3 mb-0">Все заявки на просмотр</h1><a href="index.php?page=admin" class="btn btn-outline-secondary">← Назад в админку</a></div>
<?php if ($success !== ''): ?><div class="alert alert-success"><?= $e($success) ?></div><?php endif; ?>
<?php if ($error !== ''): ?><div class="alert alert-danger"><?= $e($error) ?></div><?php endif; ?>
<div class="card shadow-sm"><div class="card-body"><?php if ($requests !== []): ?><div class="table-responsive"><table class="table table-bordered table-striped align-middle"><thead><tr><th>ID</th><th>Дата</th><th>Пользователь</th><th>Клиент</th><th>Объект</th><th>Цена</th><th>Желаемая дата</th><th>Статус</th><th>Комментарий</th><th>Действие</th></tr></thead><tbody>
<?php foreach ($requests as $request): ?><tr><td><?= (int) $request['request_id'] ?></td><td><?= $e(date('d.m.Y H:i', strtotime($request['created_at']))) ?></td><td><?= $e($request['user_email']) ?></td><td><div><strong><?= $e($request['client_name']) ?></strong></div><div><?= $e($request['client_phone']) ?></div><div class="text-muted small"><?= $e($request['client_email'] ?: '-') ?></div></td><td><div><a href="index.php?page=property&id=<?= (int) $request['property_id'] ?>"><?= $e($request['property_title']) ?></a></div><div class="text-muted small"><?= $e($request['district_name']) ?></div></td><td><?= number_format((float) $request['property_price'], 0, ',', ' ') ?> ₽</td><td><?= $e($request['preferred_date'] ? date('d.m.Y', strtotime($request['preferred_date'])) : '-') ?></td><td><?= $request['status'] === 'processed' ? '<span class="badge bg-success">Обработана</span>' : '<span class="badge bg-primary">Новая</span>' ?></td><td><?= nl2br($e($request['comment'] ?: '-')) ?></td><td><form action="index.php?page=admin_request_status" method="POST" class="d-grid gap-2"><input type="hidden" name="csrf_token" value="<?= $e($csrf()) ?>"><input type="hidden" name="request_id" value="<?= (int) $request['request_id'] ?>"><select name="status" class="form-select form-select-sm"><option value="new" <?= $request['status'] === 'new' ? 'selected' : '' ?>>Новая</option><option value="processed" <?= $request['status'] === 'processed' ? 'selected' : '' ?>>Обработана</option></select><button type="submit" class="btn btn-sm btn-dark">Сохранить</button></form></td></tr><?php endforeach; ?>
</tbody></table></div><?php else: ?><p class="text-muted mb-0">Заявок пока нет.</p><?php endif; ?></div></div></div>
